1	import { eq, and, isNull, inArray, desc, count, sql } from 'drizzle-orm';
2	import { portfolioItems, portfolioTags, portfolioItemTags, portfolioCategories } from '@studioops/db/schema';
3	import type { PostgresJsDatabase } from 'drizzle-orm/postgres-js';
4	import type { ProcessingStatus } from '../../core/domain/media-validation';
5	type Database = PostgresJsDatabase<any>;
6	
7	export interface PortfolioItemRecord {
8	  id: string;
9	  merchantId: string;
10	  originalOrgId: string;
11	  categoryId: string | null;
12	  title: string;
13	  description: string | null;
14	  mediaType: 'photo' | 'video';
15	  status: ProcessingStatus;
16	  originalPath: string;
17	  processedPath: string | null;
18	  previewPath: string | null;
19	  mimeType: string;
20	  fileSizeBytes: number;
21	  width: number | null;
22	  height: number | null;
23	  widthInches: string | null;
24	  heightInches: string | null;
25	  durationSeconds: number | null;
26	  errorDetail: string | null;
27	  createdAt: Date;
28	  updatedAt: Date;
29	}
30	
31	export interface TagRecord {
32	  id: string;
33	  name: string;
34	}
35	
36	export class DrizzlePortfolioRepository {
37	  constructor(private db: Database) {}
38	
39	  async createItem(data: {
40	    merchantId: string;
41	    originalOrgId: string;
42	    categoryId?: string;
43	    title: string;
44	    description?: string;
45	    mediaType: 'photo' | 'video';
46	    originalPath: string;
47	    mimeType: string;
48	    fileSizeBytes: number;
49	  }): Promise<PortfolioItemRecord> {
50	    const [row] = await this.db.insert(portfolioItems).values({
51	      merchantId: data.merchantId,
52	      originalOrgId: data.originalOrgId,
53	      categoryId: data.categoryId || null,
54	      title: data.title,
55	      description: data.description || null,
56	      mediaType: data.mediaType,
57	      originalPath: data.originalPath,
58	      mimeType: data.mimeType,
59	      fileSizeBytes: data.fileSizeBytes,
60	      status: 'pending',
61	    }).returning();
62	    return this.toRecord(row);
63	  }
64	
65	  async findById(id: string): Promise<PortfolioItemRecord | null> {
66	    const rows = await this.db.select().from(portfolioItems)
67	      .where(and(eq(portfolioItems.id, id), isNull(portfolioItems.deletedAt)))
68	      .limit(1);
69	    return rows[0] ? this.toRecord(rows[0]) : null;
70	  }
71	
72	  async updateProcessingResult(id: string, data: {
73	    status: ProcessingStatus;
74	    processedPath?: string;
75	    previewPath?: string;
76	    width?: number;
77	    height?: number;
78	    widthInches?: string;
79	    heightInches?: string;
80	    durationSeconds?: number;
81	    errorDetail?: string;
82	  }): Promise<void> {
83	    const updateData: any = { status: data.status, updatedAt: new Date() };
84	    if (data.processedPath) updateData.processedPath = data.processedPath;
85	    if (data.previewPath) updateData.previewPath = data.previewPath;
86	    if (data.width) updateData.width = data.width;
87	    if (data.height) updateData.height = data.height;
88	    if (data.widthInches) updateData.widthInches = data.widthInches;
89	    if (data.heightInches) updateData.heightInches = data.heightInches;
90	    if (data.durationSeconds) updateData.durationSeconds = data.durationSeconds;
91	    if (data.errorDetail) updateData.errorDetail = data.errorDetail;
92	
93	    await this.db.update(portfolioItems).set(updateData).where(eq(portfolioItems.id, id));
94	  }
95	
96	  async listItems(params: {
97	    merchantId?: string;
98	    orgScope?: string[];
99	    categoryId?: string;
100	    status?: string;
101	    page: number;
102	    limit: number;
103	  }): Promise<{ data: PortfolioItemRecord[]; total: number }> {
104	    const { page, limit, merchantId, orgScope, categoryId, status } = params;
105	    const offset = (page - 1) * limit;
106	    const conditions: any[] = [isNull(portfolioItems.deletedAt)];
107	
108	    if (merchantId) conditions.push(eq(portfolioItems.merchantId, merchantId));
109	    if (orgScope !== undefined) {
110	      if (orgScope.length > 0) conditions.push(inArray(portfolioItems.originalOrgId, orgScope));
111	      else conditions.push(sql`false`); // empty scope = no access
112	    }
113	    if (categoryId) conditions.push(eq(portfolioItems.categoryId, categoryId));
114	    if (status) conditions.push(eq(portfolioItems.status, status as any));
115	
116	    const where = and(...conditions);
117	
118	    const [totalResult] = await this.db.select({ count: count() }).from(portfolioItems).where(where);
119	    const total = totalResult?.count ?? 0;
120	
121	    const rows = await this.db.select().from(portfolioItems)
122	      .where(where)
123	      .orderBy(desc(portfolioItems.createdAt))
124	      .limit(limit)
125	      .offset(offset);
126	
127	    return { data: rows.map(this.toRecord), total };
128	  }
129	
130	  async softDelete(id: string): Promise<void> {
131	    await this.db.update(portfolioItems)
132	      .set({ deletedAt: new Date(), updatedAt: new Date() })
133	      .where(eq(portfolioItems.id, id));
134	  }
135	
136	  async getOrCreateTag(name: string): Promise<TagRecord> {
137	    const normalized = name.trim().toLowerCase();
138	    const existing = await this.db.select().from(portfolioTags)
139	      .where(eq(portfolioTags.name, normalized)).limit(1);
140	    if (existing[0]) return existing[0];
141	
142	    const [created] = await this.db.insert(portfolioTags)
143	      .values({ name: normalized })
144	      .onConflictDoNothing()
145	      .returning();
146	    if (created) return created;
147	
148	    // Race condition: another insert won
149	    const [found] = await this.db.select().from(portfolioTags)
150	      .where(eq(portfolioTags.name, normalized)).limit(1);
151	    return found;
152	  }
153	
154	  async setItemTags(itemId: string, tagIds: string[]): Promise<void> {
155	    // Delete existing tags
156	    await this.db.delete(portfolioItemTags).where(eq(portfolioItemTags.itemId, itemId));
157	    // Insert new ones
158	    if (tagIds.length > 0) {
159	      await this.db.insert(portfolioItemTags)
160	        .values(tagIds.map((tagId) => ({ itemId, tagId })))
161	        .onConflictDoNothing();
162	    }
163	  }
164	
165	  async getItemTags(itemId: string): Promise<TagRecord[]> {
166	    const rows = await this.db.select({ id: portfolioTags.id, name: portfolioTags.name })
167	      .from(portfolioItemTags)
168	      .innerJoin(portfolioTags, eq(portfolioItemTags.tagId, portfolioTags.id))
169	      .where(eq(portfolioItemTags.itemId, itemId));
170	    return rows;
171	  }
172	
173	  async listTags(search?: string): Promise<TagRecord[]> {
174	    if (search) {
175	      return this.db.select().from(portfolioTags)
176	        .where(sql`${portfolioTags.name} ILIKE ${'%' + search + '%'}`)
177	        .limit(50);
178	    }
179	    return this.db.select().from(portfolioTags).limit(100);
180	  }
181	
182	  async listCategories(merchantId: string): Promise<Array<{ id: string; name: string; sortOrder: number }>> {
183	    return this.db.select().from(portfolioCategories)
184	      .where(eq(portfolioCategories.merchantId, merchantId))
185	      .orderBy(portfolioCategories.sortOrder);
186	  }
187	
188	  async createCategory(merchantId: string, name: string, sortOrder: number): Promise<{ id: string; name: string; sortOrder: number }> {
189	    const [row] = await this.db.insert(portfolioCategories).values({ merchantId, name, sortOrder }).returning();
190	    return { id: row.id, name: row.name, sortOrder: row.sortOrder };
191	  }
192	
193	  async updateCategory(categoryId: string, merchantId: string, data: { name?: string; sortOrder?: number }): Promise<{ id: string; name: string; sortOrder: number } | null> {
194	    const existing = await this.db.select().from(portfolioCategories)
195	      .where(and(eq(portfolioCategories.id, categoryId), eq(portfolioCategories.merchantId, merchantId))).limit(1);
196	    if (!existing[0]) return null;
197	
198	    const updateData: any = {};
199	    if (data.name !== undefined) updateData.name = data.name;
200	    if (data.sortOrder !== undefined) updateData.sortOrder = data.sortOrder;
201	
202	    const [row] = await this.db.update(portfolioCategories).set(updateData)
203	      .where(eq(portfolioCategories.id, categoryId)).returning();
204	    return { id: row.id, name: row.name, sortOrder: row.sortOrder };
205	  }
206	
207	  async deleteCategory(categoryId: string, merchantId: string): Promise<void> {
208	    await this.db.delete(portfolioCategories)
209	      .where(and(eq(portfolioCategories.id, categoryId), eq(portfolioCategories.merchantId, merchantId)));
210	  }
211	
212	  async updateItemCategory(itemId: string, categoryId: string | null): Promise<void> {
213	    await this.db.update(portfolioItems).set({ categoryId, updatedAt: new Date() })
214	      .where(eq(portfolioItems.id, itemId));
215	  }
216	
217	  async countTodayUploads(merchantId: string): Promise<number> {
218	    const startOfDay = new Date();
219	    startOfDay.setHours(0, 0, 0, 0);
220	
221	    const [result] = await this.db.select({ count: count() }).from(portfolioItems)
222	      .where(and(
223	        eq(portfolioItems.merchantId, merchantId),
224	        sql`${portfolioItems.createdAt} >= ${startOfDay}`,
225	      ));
226	    return result?.count ?? 0;
227	  }
228	
229	  private toRecord(row: typeof portfolioItems.$inferSelect): PortfolioItemRecord {
230	    return {
231	      id: row.id,
232	      merchantId: row.merchantId,
233	      originalOrgId: row.originalOrgId,
234	      categoryId: row.categoryId,
235	      title: row.title,
236	      description: row.description,
237	      mediaType: row.mediaType,
238	      status: row.status as ProcessingStatus,
239	      originalPath: row.originalPath,
240	      processedPath: row.processedPath,
241	      previewPath: row.previewPath,
242	      mimeType: row.mimeType,
243	      fileSizeBytes: row.fileSizeBytes,
244	      width: row.width,
245	      height: row.height,
246	      widthInches: row.widthInches,
247	      heightInches: row.heightInches,
248	      durationSeconds: row.durationSeconds,
249	      errorDetail: row.errorDetail,
250	      createdAt: row.createdAt,
251	      updatedAt: row.updatedAt,
252	    };
253	  }
254	}
