1	import { FastifyInstance } from 'fastify';
2	import { join } from 'node:path';
3	import { mkdir, writeFile } from 'node:fs/promises';
4	import { randomUUID } from 'node:crypto';
5	import { MEDIA, QUOTAS } from '@studioops/shared';
6	import { validateFile } from '../../core/domain/media-validation';
7	import { DrizzlePortfolioRepository } from '../../infrastructure/persistence/portfolio-repository';
8	import { DrizzleCleansingRepository } from '../../infrastructure/persistence/cleansing-repository';
9	import { processImage } from '../../infrastructure/media/image-processor';
10	import { processVideo } from '../../infrastructure/media/video-processor';
11	import { normalizeDuration, pixelsToInches, normalizeCurrency, detectOutlier } from '../../core/domain/normalizers';
12	
13	const MAX_FILE_SIZE = 500 * 1024 * 1024; // 500MB
14	
15	export default async function portfolioRoutes(fastify: FastifyInstance) {
16	  const portfolioRepo = new DrizzlePortfolioRepository(fastify.db);
17	  const cleansingRepo = new DrizzleCleansingRepository(fastify.db);
18	  const storageRoot = fastify.appConfig?.STORAGE_ROOT || process.env.STORAGE_ROOT || './data/media';
19	
20	  // POST /portfolio/upload (with rules-engine quota enforcement)
21	  fastify.post('/upload', {
22	    preHandler: [fastify.authenticate, fastify.authorize('portfolio', 'upload'), fastify.enforceQuota('daily_upload_limit')],
23	  }, async (request, reply) => {
24	    const data = await request.file();
25	    if (!data) {
26	      return reply.status(400).send({ error: 'VALIDATION_ERROR', message: 'No file uploaded' });
27	    }
28	
29	    const mimeType = data.mimetype;
30	    const fileBuffer = await data.toBuffer();
31	    const fileSizeBytes = fileBuffer.length;
32	
33	    // Validate file
34	    const validation = validateFile(mimeType, fileSizeBytes, MAX_FILE_SIZE);
35	    if (!validation.valid) {
36	      return reply.status(422).send({
37	        error: validation.errorCode,
38	        message: validation.error,
39	      });
40	    }
41	
42	    // Quota is enforced by rules-engine preHandler (daily_upload_limit rule)
43	
44	    // Get org from authContext; for admin (orgScope is undefined), look up org membership directly
45	    let orgId = request.authContext?.orgScope?.[0];
46	    if (!orgId && request.user.role === 'administrator') {
47	      const { DrizzlePermissionRepository } = await import('../../infrastructure/persistence/permission-repository');
48	      const permRepo = new DrizzlePermissionRepository(fastify.db);
49	      const adminOrgs = await permRepo.getOrgIdsForUser(request.user.sub);
50	      orgId = adminOrgs[0];
51	    }
52	    if (!orgId) {
53	      return reply.status(403).send({ error: 'FORBIDDEN', message: 'No organization assigned' });
54	    }
55	
56	    // Write original file to disk
57	    const fileId = randomUUID();
58	    const ext = mimeType.split('/')[1] === 'quicktime' ? 'mov' : mimeType.split('/')[1];
59	    const relativePath = join(orgId, 'originals', `${fileId}.${ext}`);
60	    const absolutePath = join(storageRoot, relativePath);
61	
62	    await mkdir(join(storageRoot, orgId, 'originals'), { recursive: true });
63	    await writeFile(absolutePath, fileBuffer);
64	
65	    // Parse title from fields or filename
66	    const fields = data.fields as any;
67	    const title = fields?.title?.value || data.filename || 'Untitled';
68	    const description = fields?.description?.value || null;
69	    const categoryId = fields?.categoryId?.value || null;
70	
71	    // Create DB record with status=pending
72	    const item = await portfolioRepo.createItem({
73	      merchantId: request.user.sub,
74	      originalOrgId: orgId,
75	      categoryId,
76	      title,
77	      description,
78	      mediaType: validation.mediaType!,
79	      originalPath: relativePath,
80	      mimeType,
81	      fileSizeBytes,
82	    });
83	
84	    // Async processing (fire-and-forget for photos, synchronous for now)
85	    if (validation.mediaType === 'photo') {
86	      // Process image in background
87	      const outputDir = join(storageRoot, orgId);
88	      processImage(absolutePath, outputDir, fileId)
89	        .then(async (result) => {
90	          await portfolioRepo.updateProcessingResult(item.id, {
91	            status: 'ready',
92	            processedPath: join(orgId, 'processed', `${fileId}.jpg`),
93	            previewPath: join(orgId, 'previews', `${fileId}.jpg`),
94	            width: result.width,
95	            height: result.height,
96	            widthInches: pixelsToInches(result.width).toFixed(2),
97	            heightInches: pixelsToInches(result.height).toFixed(2),
98	          });
99	        })
100	        .catch(async (err) => {
101	          request.log.error({ err, itemId: item.id }, 'Media processing failed');
102	          await portfolioRepo.updateProcessingResult(item.id, {
103	            status: 'failed',
104	            errorDetail: (err as Error).message,
105	          });
106	        });
107	    } else if (validation.mediaType === 'video') {
108	      // Process video: transcode to 1080p H.264, extract poster frame
109	      const outputDir = join(storageRoot, orgId);
110	      processVideo(absolutePath, outputDir, fileId)
111	        .then(async (result) => {
112	          await portfolioRepo.updateProcessingResult(item.id, {
113	            status: 'ready',
114	            processedPath: join(orgId, 'processed', `${fileId}.mp4`),
115	            previewPath: join(orgId, 'previews', `${fileId}.jpg`),
116	            width: result.width,
117	            height: result.height,
118	            durationSeconds: result.durationSeconds,
119	          });
120	        })
121	        .catch(async (err) => {
122	          request.log.error({ err, itemId: item.id }, 'Video processing failed');
123	          await portfolioRepo.updateProcessingResult(item.id, {
124	            status: 'failed',
125	            errorDetail: (err as Error).message,
126	          });
127	        });
128	    }
129	
130	    request.auditContext = { resourceType: 'portfolio', resourceId: item.id, action: 'portfolio.upload', afterState: item };
131	    await request.writeAudit();
132	
133	    // Auto-cleansing on upload metadata (fire-and-forget)
134	    (async () => {
135	      try {
136	        // Normalize dimensions: convert file pixel dimensions to inches at 300 DPI and persist
137	        const widthInches = item.width ? pixelsToInches(item.width) : null;
138	        const heightInches = item.height ? pixelsToInches(item.height) : null;
139	
140	        if (widthInches !== null || heightInches !== null) {
141	          await portfolioRepo.updateProcessingResult(item.id, {
142	            status: item.status || 'pending',
143	            widthInches: widthInches !== null ? widthInches.toFixed(2) : undefined,
144	            heightInches: heightInches !== null ? heightInches.toFixed(2) : undefined,
145	          });
146	        }
147	
148	        // Flag missing metadata
149	        if (!item.title || item.title.trim().length === 0) {
150	          await cleansingRepo.createFlag({ recordType: 'portfolio_item', recordId: item.id, field: 'title', issue: 'MISSING' });
151	        }
152	
153	        // Flag if file size is suspiciously large (> 200MB for photos)
154	        if (item.mediaType === 'photo' && item.fileSizeBytes > 200 * 1024 * 1024) {
155	          await cleansingRepo.createFlag({ recordType: 'portfolio_item', recordId: item.id, field: 'fileSize', issue: 'OUTLIER', detail: { bytes: item.fileSizeBytes } });
156	        }
157	
158	        // Flag if normalized dimensions are unusually small (< 2 inches on any side for photos)
159	        if (item.mediaType === 'photo' && widthInches !== null && heightInches !== null) {
160	          if (widthInches < 2 || heightInches < 2) {
161	            await cleansingRepo.createFlag({
162	              recordType: 'portfolio_item', recordId: item.id, field: 'dimensions', issue: 'OUTLIER',
163	              detail: { widthInches: widthInches.toFixed(2), heightInches: heightInches.toFixed(2), note: 'Dimensions below 2 inches at 300 DPI' },
164	            });
165	          }
166	        }
167	
168	        // Dedup: check for near-identical portfolio items in same org by title
169	        const existingItems = await portfolioRepo.listItems({ orgScope: [orgId], page: 1, limit: 100 });
170	        for (const existing of existingItems.data) {
171	          if (existing.id === item.id) continue;
172	          // Simple title similarity check
173	          const titleA = item.title.toLowerCase().trim();
174	          const titleB = existing.title.toLowerCase().trim();
175	          if (titleA === titleB && item.mimeType === existing.mimeType) {
176	            await cleansingRepo.createCandidate({
177	              recordType: 'portfolio_item', recordAId: item.id, recordBId: existing.id,
178	              similarityScore: 0.95, featureScores: { title: 1.0, mimeType: 1.0 },
179	            });
180	          }
181	        }
182	      } catch (err) {
183	        fastify.log.error({ err, itemId: item.id }, 'Portfolio auto-cleansing failed');
184	      }
185	    })();
186	
187	    return reply.status(202).send({ id: item.id, status: 'pending', title: item.title, createdAt: item.createdAt });
188	  });
189	
190	  // GET /portfolio
191	  fastify.get('/', {
192	    preHandler: [fastify.authenticate, fastify.authorize('portfolio', 'read')],
193	  }, async (request, reply) => {
194	    const query = request.query as { page?: string; limit?: string; categoryId?: string; status?: string };
195	    const page = Math.max(1, parseInt(query.page || '1', 10));
196	    const limit = Math.min(100, Math.max(1, parseInt(query.limit || '20', 10)));
197	
198	    const isMerchant = request.user.role === 'merchant';
199	    const result = await portfolioRepo.listItems({
200	      merchantId: isMerchant ? request.user.sub : undefined,
201	      orgScope: request.authContext?.orgScope,
202	      categoryId: query.categoryId,
203	      status: query.status,
204	      page,
205	      limit,
206	    });
207	
208	    return reply.status(200).send({
209	      data: result.data,
210	      meta: { page, limit, total: result.total, totalPages: Math.ceil(result.total / limit) },
211	    });
212	  });
213	
214	  // GET /portfolio/:id (with org-scope/ownership enforcement)
215	  fastify.get('/:id', {
216	    preHandler: [fastify.authenticate, fastify.authorize('portfolio', 'read')],
217	  }, async (request, reply) => {
218	    const { id } = request.params as { id: string };
219	    const item = await portfolioRepo.findById(id);
220	    if (!item) return reply.status(404).send({ error: 'NOT_FOUND', message: 'Portfolio item not found' });
221	
222	    // Object-level auth: enforce per-role access
223	    if (request.user.role === 'administrator') {
224	      // Admin sees all — no restriction
225	    } else if (request.user.role === 'merchant') {
226	      // Merchant sees only own items
227	      if (item.merchantId !== request.user.sub) {
228	        return reply.status(404).send({ error: 'NOT_FOUND', message: 'Portfolio item not found' });
229	      }
230	    } else {
231	      // Operations, Client, Guest: must have item's org in scope
232	      const orgScope = request.authContext?.orgScope ?? [];
233	      if (!orgScope.includes(item.originalOrgId)) {
234	        return reply.status(404).send({ error: 'NOT_FOUND', message: 'Portfolio item not found' });
235	      }
236	    }
237	
238	    const tags = await portfolioRepo.getItemTags(id);
239	    return reply.status(200).send({ ...item, tags });
240	  });
241	
242	  // DELETE /portfolio/:id
243	  fastify.delete('/:id', {
244	    preHandler: [fastify.authenticate, fastify.authorize('portfolio', 'delete')],
245	  }, async (request, reply) => {
246	    const { id } = request.params as { id: string };
247	    const item = await portfolioRepo.findById(id);
248	    if (!item) return reply.status(404).send({ error: 'NOT_FOUND', message: 'Portfolio item not found' });
249	
250	    if (request.user.role === 'merchant' && item.merchantId !== request.user.sub) {
251	      return reply.status(403).send({ error: 'FORBIDDEN', message: 'You do not own this resource' });
252	    }
253	    if (request.user.role === 'operations') {
254	      const orgScope = request.authContext?.orgScope ?? [];
255	      if (!orgScope.includes(item.originalOrgId)) {
256	        return reply.status(404).send({ error: 'NOT_FOUND', message: 'Portfolio item not found' });
257	      }
258	    }
259	
260	    await portfolioRepo.softDelete(id);
261	    request.auditContext = { resourceType: 'portfolio', resourceId: id, beforeState: item };
262	    await request.writeAudit();
263	    return reply.status(204).send();
264	  });
265	
266	  // PATCH /portfolio/:id/tags
267	  fastify.patch('/:id/tags', {
268	    preHandler: [fastify.authenticate, fastify.authorize('portfolio', 'update'), fastify.enforceQuota('hourly_portfolio_edit_limit')],
269	  }, async (request, reply) => {
270	    const { id } = request.params as { id: string };
271	    const { tagNames } = request.body as { tagNames?: string[] };
272	
273	    if (!tagNames || !Array.isArray(tagNames)) {
274	      return reply.status(400).send({ error: 'VALIDATION_ERROR', message: 'tagNames array is required' });
275	    }
276	
277	    const item = await portfolioRepo.findById(id);
278	    if (!item) return reply.status(404).send({ error: 'NOT_FOUND', message: 'Portfolio item not found' });
279	
280	    if (request.user.role === 'merchant' && item.merchantId !== request.user.sub) {
281	      return reply.status(403).send({ error: 'FORBIDDEN', message: 'You do not own this resource' });
282	    }
