219	      }
220	      this.cancelForm();
221	      this.load();
222	    } catch (err) {
223	      this.notifications.error(err instanceof HttpErrorResponse ? (err.error?.message || 'Save failed') : 'Save failed');
224	    } finally { this.submitting.set(false); }
225	  }
226	
